#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) {
        // Serialize packet_id using arithmetic serialization
        stream << packet_id;

        // Serialize username with prefix using prefixed adaptor
        stream << hexi::prefixed(username);

        // Serialize scores vector with count prefix using prefixed adaptor
        stream << hexi::prefixed(scores);

        // Serialize metadata as null-terminated string using null_terminated adaptor
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::buffer_adaptor adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Call the packet's serialise method with the stream
    packet.serialise(stream);

    // Return the buffer containing the serialized data
    return buffer;
}
```

## Key Implementation Points:

1. **Packet ID Serialization**: Uses direct arithmetic serialization with `stream << packet_id`

2. **Username Serialization**: Uses `hexi::prefixed(username)` adaptor which automatically handles length prefixing for strings

3. **Scores Vector Serialization**: Uses `hexi::prefixed(scores)` adaptor which writes the count first followed by the elements, leveraging the `write_container` functionality

4. **Metadata Serialization**: Uses `hexi::null_terminated(metadata)` adaptor for null-terminated string serialization

5. **Buffer Management**: Properly creates and returns the buffer containing all serialized data

The implementation follows the Hexi library conventions and correctly utilizes the provided adaptors for different data types as specified in the assessment objectives.

