```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>
#include <span>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;
};

NetworkPacket deserialize_packet(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    NetworkPacket packet;

    // Read packet_id using arithmetic read
    adaptor >> packet.packet_id;

    // Read username with prefixed length
    adaptor >> hexi::prefixed(packet.username);

    // Read scores vector: first read count, then use read_container
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.read_container(packet.scores, score_count);

    // Read metadata as null-terminated string
    adaptor >> hexi::null_terminated(packet.metadata);

    // Skip any remaining padding bytes
    adaptor.skip(adaptor.read_max());

    return packet;
}

struct PacketInfo {
    uint32_t packet_id;
    std::string_view username;
};

PacketInfo extract_packet_info(const std::span<const uint8_t> buffer) {
    // Create buffer_adaptor from input buffer
    hexi::buffer_adaptor<std::span<const uint8_t>> adaptor(buffer);

    PacketInfo info;

    // Use span() for packet_id (zero-copy view of first 4 bytes)
    auto id_span = adaptor.span<uint32_t>(1);
    info.packet_id = *id_span.data();

    // Read username using prefixed adaptor to get string_view
    adaptor >> hexi::prefixed(info.username);

    // Skip the scores vector: read count, then skip the data
    uint32_t score_count;
    adaptor >> score_count;
    adaptor.skip(score_count * sizeof(uint32_t));

    return info;
}
```

