```cpp
#include <hexi/hexi.h>
#include <vector>
#include <cstdint>

std::vector<uint8_t> read_buffer_data(const std::vector<uint8_t>& source_buffer, size_t bytes_to_read) {
    // Create buffer_adaptor object using source_buffer
    hexi::buffer_adaptor<const std::vector<uint8_t>> ba(source_buffer);

    // Check if requested bytes_to_read is within available data
    if (bytes_to_read > ba.size()) {
        HEXI_THROW(hexi::buffer_underrun(bytes_to_read, ba.size(), ba.size()));
    }

    // Create destination buffer and use read function to copy data
    std::vector<uint8_t> destination(bytes_to_read);
    ba.read(destination.data(), bytes_to_read);

    return destination;
}

void write_buffer_data(std::vector<uint8_t>& dest_buffer, const std::vector<uint8_t>& source_data) {
    // Create buffer_adaptor object using dest_buffer
    hexi::buffer_adaptor<std::vector<uint8_t>> ba(dest_buffer);

    // Check if there is enough space in buffer_adaptor to write source_data
    if (source_data.size() > ba.free()) {
        HEXI_THROW(hexi::buffer_overflow(source_data.size(), ba.free(), ba.size()));
    }

    // Use write function to copy data from source to buffer
    ba.write(source_data.data(), source_data.size());
}
