    hexi::buffer_adaptor<std::vector<uint8_t>> ba(dest_buffer);

    // Check if there is enough space in buffer_adaptor to write source_data
    if (source_data.size() > ba.free()) {
        HEXI_THROW(hexi::buffer_overflow(source_data.size(), ba.free(), ba.size()));
