    uint32_t item_count;
    size_t required_bytes;

    // Create a binary_stream from the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor, 0);

    // Read the item_count using binary_stream
    stream.get(&item_count, 1);

    // Calculate required bytes based on data_type
    if (result.data_type == 0) {
