```cpp
#include <hexi/file_buffer.h>
#include <vector>
#include <cstdint>
#include <filesystem>
#include <stdexcept>

std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    if (bytes_to_read > buffer.size()) {
        throw std::runtime_error("Requested to read more bytes than available in file");
    }

    std::vector<uint8_t> result(bytes_to_read);
    buffer.read(result.data(), bytes_to_read);

    return result;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    if (bytes_to_preview > buffer.size()) {
        throw std::runtime_error("Requested to preview more bytes than available in file");
    }

    std::vector<uint8_t> result(bytes_to_preview);
    buffer.copy(result.data(), bytes_to_preview);

    return result;
}

void write_file_data(const std::filesystem::path& file_path, const std::vector<uint8_t>& data) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    if (!data.empty()) {
        buffer.write(data.data(), data.size());
    }
}

size_t get_file_size(const std::filesystem::path& file_path) {
    hexi::file_buffer buffer(file_path);

    if (!buffer) {
        throw std::runtime_error("Failed to open file: " + file_path.string());
    }

    return buffer.size();
}
```

## Key Implementation Points:

1. **File Buffer Creation**: Uses `hexi::file_buffer` constructor with `std::filesystem::path` parameter
2. **Error Handling**: Checks buffer validity using the boolean operator (`if (!buffer)`)
3. **Bounds Checking**: Validates that requested byte counts don't exceed available file size
4. **Memory Management**: Properly sized `std::vector<uint8_t>` for return values
5. **Function Mapping**:
   - `read_file_data` → `file_buffer::read()`
   - `preview_file_data` → `file_buffer::copy()` (non-destructive preview)
   - `write_file_data` → `file_buffer::write()`
   - `get_file_size` → `file_buffer::size()`
6. **Exception Safety**: Throws appropriate exceptions for error conditions

The implementation follows all specified requirements and properly utilizes the `hexi::file_buffer` API as documented in the reference materials.

