#include <hexi/file_buffer.h>
#include <cstdint>
#include <filesystem>

uint32_t read_uint32_from_file(const std::filesystem::path& file_path) {
    // Create a file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file_buffer is in a valid state (no errors)
    if (buffer.error()) {
        return 0; // Return default value on error
    }

    // Use the template read method to read a uint32_t value
    uint32_t value;
    buffer.read(&value);

    // Return the read value
    return value;
}

void write_uint32_to_file(const std::filesystem::path& file_path, uint32_t value) {
    // Create a file_buffer object using the provided file path
    hexi::file_buffer buffer(file_path);

    // Check if the file_buffer is in a valid state (no errors)
    if (buffer.error()) {
        return; // Do nothing on error
    }

    // Use the template write method to write the uint32_t value
    buffer.write(value);

    // The file_buffer destructor will automatically flush and close the file
}
```

