struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: convert to little-endian before writing
        adaptor.write(sensor_id);

        for (auto& temp : temperatures) {
            auto converted = hexi::endian::conditional_reverse(temp, 
                                                            std::endian::native, 
                                                            std::endian::little);
            adaptor.write(converted);
        }

        auto converted_pressure = hexi::endian::conditional_reverse(pressure,
                                                         std::endian::native,
                                                         std::endian::little);
        adaptor.write(converted_pressure);
    }

    void serialise(auto& adaptor) {
        // Deserialization: read then convert from little-endian to native
        adaptor.read(sensor_id);

        // Read temperatures
        temperatures.clear();
        for (size_t i = 0; i < temperatures.size(); ++i) {
            float temp;
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
            temperatures.push_back(temp);
        }

        // Read pressure
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
